os.makedirs(os.path.dirname("src/app/stats/page.tsx"), exist_ok=True)
open("src/app/stats/page.tsx", "wb").write(base64.b64decode(""))
os.makedirs(os.path.dirname("src/components/collection/SuggestModal.tsx"), exist_ok=True)
